import sys

def main():
    s = list(map(int, sys.stdin.read().split()))
    # Check condition 2 and 3: all values between 100 and 675 inclusive, and multiples of 25
    for num in s:
        if not (100 <= num <= 675) or num % 25 != 0:
            print("No")
            return
    # Check condition 1: monotonically non-decreasing
    for i in range(7):
        if s[i] > s[i + 1]:
            print("No")
            return
    print("Yes")

if __name__ == "__main__":
    main()
